from flask import Flask, jsonify, request
import os
import json
import time
import hashlib

app = Flask(__name__)
CACHE_DIR = "cache"
CACHE_EXPIRATION = 60  # seconds

if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def get_cache_key(api_endpoint, params):
    key = f"{api_endpoint}::{json.dumps(params, sort_keys=True)}"
    return hashlib.md5(key.encode()).hexdigest()

def cache_response(key, data):
    with open(os.path.join(CACHE_DIR, key), 'w') as f:
        json.dump({'timestamp': time.time(), 'data': data}, f)

def load_cache(key):
    try:
        with open(os.path.join(CACHE_DIR, key), 'r') as f:
            cached = json.load(f)
            if time.time() - cached['timestamp'] < CACHE_EXPIRATION:
                return cached['data']
            else:
                os.remove(os.path.join(CACHE_DIR, key))  # Remove expired cache
    except (FileNotFoundError, json.JSONDecodeError):
        return None

@app.route('/api/data', methods=['GET'])
def get_data():
    params = request.args.to_dict()
    cache_key = get_cache_key(request.path, params)
    cached_data = load_cache(cache_key)

    if cached_data is not None:
        return jsonify(cached_data)

    # Simulate expensive data fetching
    response_data = {"message": "Fetched data", "params": params}
    cache_response(cache_key, response_data)
    return jsonify(response_data)

if __name__ == '__main__':
    app.run(debug=True)